int bitmapCharWidth(const BitmapFont& font, int character) {
	if (character < 0 || character >= font.quantity) {
		return 0;
	}
	return *(font.characters[character]);
}

void drawBitmapChar(const BitmapFont& font, int character) {
	if (character < 0 || character >= font.quantity) {
		return;
	}

	const GLubyte* face = font.characters[character];

	glPushClientAttrib(GL_CLIENT_PIXEL_STORE_BIT);
	glPixelStorei(GL_UNPACK_SWAP_BYTES, GL_FALSE);
	glPixelStorei(GL_UNPACK_LSB_FIRST, GL_FALSE);
	glPixelStorei(GL_UNPACK_ROW_LENGTH, 0);
	glPixelStorei(GL_UNPACK_SKIP_ROWS, 0);
	glPixelStorei(GL_UNPACK_SKIP_PIXELS, 0);
	glPixelStorei(GL_UNPACK_ALIGNMENT, 1);

	glBitmap(face[0], font.height, font.xorig, font.yorig, static_cast<float>(face[0]), 0.0f, face + 1);

	glPopClientAttrib();
}